st.title("LOTOELITE PRO v63.2 - HISTÓRICO COMPLETO")
st.caption("✓ 6.569 concursos carregados automaticamente do GitHub")

# Abas principais
tab1, tab2, tab3, tab4, tab5 = st.tabs(["📊 Resultados", "📈 Estatísticas", "🎯 Dashboard", "🎲 Jogos", "⚙️ Config"])

with tab1:
    col1, col2 = st.columns(2)
    
    with col1:
        st.subheader("Lotofácil")
        c1, c2, c3 = st.columns(3)
        c1.metric("Concursos", f"{len(df_lf):,}".replace(",", "."))
        c2.metric("Dezenas", "25")
        c3.metric("Período", "2003-2026")
        
        st.success(f"✓ Base completa carregada")
        
        # Mostrar últimos 10
        ultimos_lf = df_lf.tail(10).copy()
        ultimos_lf['dezenas'] = ultimos_lf.apply(lambda r: ' '.join([f"{r[f'd{i}']:02d}" for i in range(1,16)]), axis=1)
        st.dataframe(ultimos_lf[['concurso','data','dezenas']].iloc[::-1], 
                    use_container_width=True, hide_index=True, height=350)
    
    with col2:
        st.subheader("Lotomania")
        c1, c2, c3 = st.columns(3)
        c1.metric("Concursos", f"{len(df_lm):,}".replace(",", "."))
        c2.metric("Dezenas", "100")
        c3.metric("Período", "1999-2026")
        
        st.success(f"✓ Base completa carregada")
        
        ultimos_lm = df_lm.tail(10).copy()
        ultimos_lm['dezenas'] = ultimos_lm.apply(lambda r: ' '.join([f"{r[f'd{i}']:02d}" for i in range(1,21)]), axis=1)
        st.dataframe(ultimos_lm[['concurso','data','dezenas']].iloc[::-1], 
                    use_container_width=True, hide_index=True, height=350)

with tab2:
    st.header("Estatísticas Completas")
    
    col1, col2 = st.columns(2)
    
    with col1:
        st.subheader("Lotofácil - Frequência (3.660 concursos)")
        freq_lf = {}
        for i in range(1, 16):
            for val in df_lf[f'd{i}']:
                freq_lf[val] = freq_lf.get(val, 0) + 1
        
        freq_df = pd.DataFrame(sorted(freq_lf.items()), columns=['Dezena','Frequência'])
        freq_df['%'] = (freq_df['Frequência'] / len(df_lf) * 100).round(2)
        st.dataframe(freq_df, use_container_width=True, hide_index=True)
    
    with col2:
        st.subheader("Lotomania - Top 20 mais sorteadas")
        freq_lm = {}
        for i in range(1, 21):
            for val in df_lm[f'd{i}']:
                freq_lm[val] = freq_lm.get(val, 0) + 1
        
        freq_df_lm = pd.DataFrame(sorted(freq_lm.items(), key=lambda x: x[1], reverse=True)[:20], 
                                 columns=['Dezena','Frequência'])
        st.dataframe(freq_df_lm, use_container_width=True, hide_index=True)

with tab3:
    st.header("Dashboard v63.2")
    col1, col2, col3, col4 = st.columns(4)
    col1.metric("Total Concursos", "6.569")
    col2.metric("Lotofácil", "3.660")
    col3.metric("Lotomania", "2.909")
    col4.metric("Atualizado", "14/04/2026")
    
    st.info("✓ Histórico completo embutido no código. Não precisa importar CSV.")

with tab4:
    st.header("Gerador Inteligente")
    st.write("Baseado em 6.569 concursos históricos")
    
    if st.button("🎲 GERAR JOGO LOTOFÁCIL", type="primary", use_container_width=True):
        # Estratégia simples: evitar números muito frios
        freq_lf = {}
        for i in range(1, 16):
            for val in df_lf[f'd{i}']:
                freq_lf[val] = freq_lf.get(val, 0) + 1
        
        # Pega os 20 mais frequentes e sorteia 15
        top20 = sorted(freq_lf.items(), key=lambda x: x[1], reverse=True)[:20]
        numeros = [n for n,_ in top20]
        jogo = sorted(random.sample(numeros, 15))
        
        st.success(f"**Jogo sugerido:** {' - '.join(f'{n:02d}' for n in jogo)}")
        st.caption("Baseado nas dezenas mais frequentes nos 3.660 concursos")

with tab5:
    st.header("Configuração")
    st.write("**Versão:** v63.2 - Histórico Completo Embutido")
    st.write("**GitHub:** dinoinadovelho74/codificador")
    st.write("**Última atualização:** 14/04/2026")
    
    st.divider()
    st.write("Para atualizar com concursos novos:")
    st.code("1. Me avise o número do novo concurso\n2. Eu gero o app.py atualizado\n3. Cole no GitHub")

st.caption("LOTOELITE PRO v63.2 | Teresina-PI | Histórico 1999-2026 completo")
